import { Avatar, AvatarImage, AvatarFallback } from '@/components/ui/avatar';
import { api } from '@/lib/api';
import type { Channel } from '@/types/task';

interface ChannelListProps {
  selected: number[];
  onSelect: (channelId: number) => void;
  searchQuery: string;
}

