  selected,
  onSelect,
  searchQuery
}) => {
  const { data: channels = [], isLoading } = useQuery<Channel[]>({
    queryKey: ['channels'],
    queryFn: async () => {
      const response = await api.getChannels();
      console.log('Raw channels response in ChannelList:', response);
      if (Array.isArray(response)) {
        return response;
      }
      return [];
    }
