            <p className="text-sm text-muted-foreground truncate">
              @{channel.username}
            </p>
          </div>
          {selected.includes(channel.id) && (
            <Check className="h-4 w-4 text-purple-500 shrink-0" />
          )}
        </button>
      ))}
    </div>
  );
};

export default ChannelList;

